(async () => {
  const CFG = {
    bright:    3,
    dim:       6,
    color:          "#e98b07",
    colorIntensity: 0.5,
    attenuation:    0.5,
    angle:          360,
    animation: {
      type:      "torch",
      speed:     1,
      intensity: 2,
      reverse:   false,
    },
    snapToGrid: true,
  };

  ui.notifications.info("Light \u25b8 click canvas to place (or Esc to cancel).");

  const pos = await new Promise((resolve, reject) => {
    const onKey = (e) => {
      if (e.key !== "Escape") return;
      cleanup();
      reject(new Error("cancelled"));
    };

    const onClick = (event) => {
      cleanup();
      resolve(event.data.getLocalPosition(canvas.stage));
    };

    const cleanup = () => {
      canvas.stage.off("click", onClick);
      window.removeEventListener("keydown", onKey);
      clearTimeout(timer);
    };

    const timer = setTimeout(() => {
      cleanup();
      reject(new Error("Light placement timed out."));
    }, 30_000);

    canvas.stage.once("click", onClick);
    window.addEventListener("keydown", onKey, { once: false });
  }).catch(err => {
    if (err.message !== "cancelled") ui.notifications.warn("Light: " + err.message);
    return null;
  });

  if (!pos) return;

  const { x, y } = CFG.snapToGrid
    ? canvas.grid.getSnappedPosition(pos.x, pos.y)
    : pos;

  await AmbientLightDocument.create({
    x, y,
    config: {
      dim:         CFG.dim,
      bright:      CFG.bright,
      color:       CFG.color,
      alpha:       CFG.colorIntensity,
      attenuation: CFG.attenuation,
      angle:       CFG.angle,
      animation:   CFG.animation,
    },
  }, { parent: canvas.scene });

  ui.notifications.info("Light placed.");
})();
